import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import ArtisanCard from '../components/ArtisanCard';

const CategoryList = () => {
    const { categoryName } = useParams();
    const [artisans, setArtisans] = useState([]);

    useEffect(() => {
        axios.get('http://localhost:5000/api/artisans/search', { params: { category: categoryName } })
            .then(res => setArtisans(res.data))
            .catch(err => console.error("Erreur API:", err));
    }, [categoryName]);

    return (
        <div className="container py-5">
            <h2 className="fw-bold mb-5" style={{ color: '#004a99' }}>Artisans : {categoryName}</h2>
            <div className="row g-4">
                {artisans.length > 0 ? (
                    artisans.map(artisan => (
                        <ArtisanCard key={artisan.id} artisan={artisan} />
                    ))
                ) : (
                    <p className="text-center">Aucun artisan trouvé pour cette catégorie.</p>
                )}
            </div>
        </div>
    );
};

export default CategoryList;
